1400	    template <typename T, bool cast_bf2half>
1401	    void allreduce(T const* A, T* B, uint32_t N, int quant_level, hipStream_t stream)
1402	    {
1403	        if(world_size != 2 && world_size != 4 && world_size != 8)
1404	        {
1405	            throw std::runtime_error("All Reduce not supported for world_size = " +
1406	                                     std::to_string(world_size));
1407	        }
1408	
1409	        // Configuration.
1410	        uint32_t msg_size   = N * sizeof(T);
1411	        uint32_t num_blocks = divceil(msg_size, kTileSize);
1412	        uint32_t grid       = min(kMaxNumBlocks, num_blocks);
1413	        auto quant_level_   = static_cast<QuickReduceQuantLevel>(quant_level);
1414	        switch(quant_level_)
1415	        {
1416	        case QuickReduceQuantLevel::FP8: TWOSHOT_DISPATCH(CodecFP8) break;
1417	        case QuickReduceQuantLevel::INT6: TWOSHOT_DISPATCH(CodecQ6) break;
1418	        case QuickReduceQuantLevel::INT4: TWOSHOT_DISPATCH(CodecQ4) break;
1419	        case QuickReduceQuantLevel::INT3: TWOSHOT_DISPATCH_TP2_ONLY(CodecQ3) break;
1420	        default: TWOSHOT_DISPATCH(CodecFP) break;
1421	        }
1422	        HIP_CHECK(hipGetLastError());
1423	        // flag color advances on-device now (see kernel), no host rotation.
1424	    }
1425	
1426	    template <typename T, typename CommT = T, bool cast_bf2half = false>
1427	    void allreduce_rmsnorm(T const* A,
1428	                           T const* residual_inp,
1429	                           T* residual_out,
1430	                           T* B,
1431	                           T const* weight,
1432	                           float eps,
1433	                           uint32_t N,
1434	                           uint32_t hidden_dim,
1435	                           int quant_level,
1436	                           hipStream_t stream)
1437	    {
1438	        if(world_size != 2 && world_size != 4 && world_size != 8)
1439	        {
1440	            throw std::runtime_error("All Reduce not supported for world_size = " +
1441	                                     std::to_string(world_size));
1442	        }
1443	        uint32_t row_bytes = hidden_dim * sizeof(T);
1444	        if(row_bytes == 0 || row_bytes > kTileSize || kTileSize % row_bytes != 0)
1445	        {
1446	            throw std::runtime_error(
1447	                "QR fused RMSNorm requires hidden_dim * element_size to divide " +
1448	                std::to_string(kTileSize));
1449	        }
1450	        if(N % hidden_dim != 0)
1451	        {
1452	            throw std::runtime_error("QR fused RMSNorm requires numel divisible by hidden_dim");
1453	        }
1454	
1455	        uint32_t msg_size   = N * sizeof(T);
1456	        uint32_t num_blocks = divceil(msg_size, kTileSize);
1457	        uint32_t grid       = min(kMaxNumBlocks, num_blocks);
1458	        auto quant_level_   = static_cast<QuickReduceQuantLevel>(quant_level);
1459	        switch(quant_level_)
1460	        {
1461	        case QuickReduceQuantLevel::FP8: TWOSHOT_RMSNORM_DISPATCH(CodecFP8) break;
1462	        case QuickReduceQuantLevel::INT6: TWOSHOT_RMSNORM_DISPATCH(CodecQ6) break;
1463	        case QuickReduceQuantLevel::INT4: TWOSHOT_RMSNORM_DISPATCH(CodecQ4) break;
1464	        default: TWOSHOT_RMSNORM_DISPATCH(CodecFP) break;
1465	        }
1466	        HIP_CHECK(hipGetLastError());
1467	        // flag color advances on-device now (see kernel), no host rotation.
1468	    }
1469	};
