24	// Setup acquire-release semantics for vector memory reads (mubuf instruction)
25	// as per architecture.
26	#if defined(__gfx942__)
27	// CDNA3: Scope bits sc0, sc1
28	#define MUBUF_ACQUIRE 16
29	#define MUBUF_RELEASE 16
30	#elif(defined(__gfx908__) || defined(__gfx90a__))
31	// CDNA1 and CDNA2 - glc bit
32	#define MUBUF_ACQUIRE 1
33	#define MUBUF_RELEASE 0
