36	static constexpr int kNegOne = 0xBC00BC00; // {-1, -1}, fp16x2_t
37	
38	// Number of atoms (4xf16x2_t) processed by a single thread
39	static constexpr int kAtoms = 8;
40	
41	// We use a workgroup of 256 threads
42	static constexpr int kBlockSize  = 256;
43	static constexpr int kAtomStride = kBlockSize;
44	
45	// Size and atom stride of source/destination data that the block will
46	// process.
47	// Workgroup scope = Tile = (256 threads x 8 atoms x 16B)
48	static constexpr int kTileSize = kBlockSize * kAtoms * sizeof(int32x4_t);
49	
50	// Max number of blocks. 304 CUs on MI300
51	static constexpr int kMaxNumBlocks = 304 * 4;
52	
53	// Standard CDNA wavefront size.
54	static constexpr int kWavefront = 64;
55	
56	// 256 thread, 4 wavefronts.
57	static dim3 constexpr kBlockTwoShot = {kWavefront, kBlockSize / kWavefront, 1};
58	
59	// Number of threads in a group for quantization
60	// It corresponds to 32 F16 elements in quantization block
61	static constexpr int kThreadGroupSize = 8;
