124	template <>
125	__quickreduce_device_inline__ void packed_assign_add<half>(int32x4_t* A, int32x4_t* B)
126	{
127	    int32x4_t& tR_fragment = A[0];
128	    int32x4_t& tA_fragment = B[0];
129	
130	    asm volatile("v_pk_add_f16 %0, %1, %2"
131	                 : "=v"(tR_fragment[0])
132	                 : "v"(tR_fragment[0]), "v"(tA_fragment[0]));
133	    asm volatile("v_pk_add_f16 %0, %1, %2"
134	                 : "=v"(tR_fragment[1])
135	                 : "v"(tR_fragment[1]), "v"(tA_fragment[1]));
136	    asm volatile("v_pk_add_f16 %0, %1, %2"
137	                 : "=v"(tR_fragment[2])
138	                 : "v"(tR_fragment[2]), "v"(tA_fragment[2]));
139	    asm volatile("v_pk_add_f16 %0, %1, %2"
140	                 : "=v"(tR_fragment[3])
141	                 : "v"(tR_fragment[3]), "v"(tA_fragment[3]));
142	}
