199	__quickreduce_device_inline__ int packed_abs_max(int a, int b);
200	
201	template <>
202	__quickreduce_device_inline__ int packed_abs_max<half>(int a, int b)
203	{
204	    half2 wmaxh2 = __builtin_bit_cast(half2, a);
205	    half2 wminh2 = __builtin_bit_cast(half2, b);
206	    half2 wblockmaxh2;
207	
208	    wblockmaxh2.x = __hgt(__habs(wmaxh2.x), __habs(wminh2.x)) ? wmaxh2.x : wminh2.x;
209	    wblockmaxh2.y = __hgt(__habs(wmaxh2.y), __habs(wminh2.y)) ? wmaxh2.y : wminh2.y;
210	    return __builtin_bit_cast(int, wblockmaxh2);
211	}
