315	__quickreduce_device_inline__ int packed_from_int16_pair(int16_t low, int16_t high);
316	
317	template <>
318	__quickreduce_device_inline__ int packed_from_int16_pair<half>(int16_t low, int16_t high)
319	{
320	    // Convert two signed integers to one fp16x2 packed 32-bit lane.
321	    half2 h =
322	        __halves2half2(__int2half_rn(static_cast<int>(low)), __int2half_rn(static_cast<int>(high)));
323	    return __builtin_bit_cast(int, h);
324	}
