326	template <>
327	__quickreduce_device_inline__ int packed_from_int16_pair<__hip_bfloat16>(int16_t low, int16_t high)
328	{
329	    // Convert two signed integers to one bf16x2 packed 32-bit lane.
330	    nv_bfloat16 bf_low  = __float2bfloat16(static_cast<float>(low));
331	    nv_bfloat16 bf_high = __float2bfloat16(static_cast<float>(high));
332	    nv_bfloat162 bf2    = __halves2bfloat162(bf_low, bf_high);
333	    return *reinterpret_cast<int*>(&bf2);
334	}
