                           T const* __restrict__ residual_inp,
                           T* __restrict__ residual_out,
                           T* __restrict__ output,
                           T const* __restrict__ weight,
                           float eps,
                           uint32_t const N,
                           uint32_t const hidden_dim,
                           int const block,
                           int const rank,
                           uint8_t** __restrict__ buffer_list,
                           uint32_t const data_offset,
                           uint32_t flag_color,
                           int64_t data_size_per_phase)
{
    // Stub: zero the outputs for this block's tile so the kernel is a no-op
    // placeholder. Replace with the real fused all-reduce + RMSNorm.
    int thread = threadIdx.x + threadIdx.y * kWavefront;
    int grid   = gridDim.x;
    for(uint32_t idx = (uint32_t)(block) * blockDim.x * blockDim.y + thread;
        idx < N;
        idx += (uint32_t)grid * blockDim.x * blockDim.y)
    {
        output[idx]       = qr_from_float<T>(0.0f);
        residual_out[idx] = qr_from_float<T>(0.0f);
    }
}

tool_use_result.newString:
    __device__ static void run(T const* __restrict__ input,
                               T const* __restrict__ residual_inp,
                               T* __restrict__ residual_out,
                               T* __restrict__ output,
                               T const* __restrict__ weight,
                               float eps,
                               uint32_t const N,
                               uint32_t const hidden_dim,
                               int const block,
                               int const rank,
                               uint8_t** __restrict__ buffer_list,
                               uint32_t const data_offset,
                               uint32_t flag_color,
                               int64_t data_size_per_phase)
    {
        // ================= Two-shot quick all-reduce =================
        // Communication is identical to AllReduceTwoshot::run; the reduced tile
        // for this block ends up gathered in `tA` (same layout as the input
        // read) and is consumed in registers by the RMSNorm epilogue below.
        int thread           = threadIdx.x + threadIdx.y * kWavefront;
        uint8_t* rank_buffer = buffer_list[rank];
        Codec codec(thread, rank);
        int block_id = blockIdx.x;
        uint8_t* buffer_ptr[kWorldSize];
        for(int i = 0; i < kWorldSize; ++i)
        {
            buffer_ptr[i] = buffer_list[i];
        }

        // Read input into registers.
        int32x4_t tA[kAtoms];

        BufferResource src_buffer(const_cast<T*>(input), N * sizeof(T));
        uint32_t src_offset = block * kTileSize + thread * sizeof(int32x4_t);

        for(int i = 0; i < kAtoms; i++)
        {
            tA[i] = buffer_load_dwordx4(src_buffer.descriptor, src_offset, 0, 0);
            src_offset += kAtomStride * sizeof(int32x4_t);
            if constexpr(cast_bf2half)
            {
                const nv_bfloat162* bf_buf = reinterpret_cast<const nv_bfloat162*>(&tA[i]);
                half2 half_buf[4];
#pragma unroll
                for(int j = 0; j < 4; ++j)
                {
                    float2 f    = __bfloat1622float2(bf_buf[j]);
                    half_buf[j] = __float22half2_rn(f);
                }
                tA[i] = *reinterpret_cast<const int32x4_t*>(half_buf);
            }
        }

        // Phase-1A: scatter this rank's segments to every rank's comm buffer.
        uint32_t comm_data0_offset = data_offset + block_id * Codec::kTransmittedTileSize;
        uint32_t comm_data1_offset = data_size_per_phase + comm_data0_offset;

        uint32_t comm_flags0_offset = block_id * (kWorldSize * sizeof(uint32_t));
        uint32_t comm_flags1_offset = (data_offset / 2) + comm_flags0_offset;

        for(int r = 0; r < kWorldSize; r++)
        {
            int32x4_t* send_buffer = reinterpret_cast<int32x4_t*>(
                buffer_ptr[r] + comm_data0_offset + rank * Codec::kRankTransmittedTileSize);
            codec.send(send_buffer, &tA[r * Codec::kRankAtoms]);
        }

        __syncthreads();
        if(thread < kWorldSize)
        {
            int r              = thread;
            uint32_t* flag_ptr = reinterpret_cast<uint32_t*>(buffer_ptr[r] + comm_flags0_offset +
                                                             rank * sizeof(uint32_t));
            set_sync_flag(flag_ptr, flag_color);
        }

        // Phase-1B: reduce the segments destined for this rank.
        int32x4_t tR[Codec::kRankAtoms] = {};
        {
            int32x4_t* recv_buffer = reinterpret_cast<int32x4_t*>(rank_buffer + comm_data0_offset);
            uint32_t* flag_ptr     = reinterpret_cast<uint32_t*>(rank_buffer + comm_flags0_offset);

            for(int r = 0; r < kWorldSize; r++)
            {
                if(thread == 0)
                {
                    wait_sync_flag(&flag_ptr[r], flag_color);
                }
                __syncthreads();

                codec.recv(&recv_buffer, tA);

                for(int i = 0; i < Codec::kRankAtoms; i++)
                {
                    packed_assign_add<CommT>(&tR[i], &tA[i]);
                }
            }
        }

        // Phase-2: broadcast the reduced segment back to every rank.
        for(int r = 0; r < kWorldSize; r++)
        {
            int32x4_t* send_buffer = reinterpret_cast<int32x4_t*>(
                buffer_ptr[r] + comm_data1_offset + rank * Codec::kRankTransmittedTileSize);
            codec.send(send_buffer, tR);
        }

        __syncthreads();
        if(thread < kWorldSize)
        {
            int r              = thread;
            uint32_t* flag_ptr = reinterpret_cast<uint32_t*>(buffer_ptr[r] + comm_flags1_offset +
                                                             rank * sizeof(uint32_t));
            set_sync_flag(flag_ptr, flag_color);
        }

        // Phase-2: gather the fully reduced tile into tA.
        {
            int32x4_t* recv_buffer = reinterpret_cast<int32x4_t*>(rank_buffer + comm_data1_offset);
            uint32_t* flag_ptr     = reinterpret_cast<uint32_t*>(rank_buffer + comm_flags1_offset);

            for(int r = 0; r < kWorldSize; r++)
            {
                if(thread == 0)
                {
                    wait_sync_flag(&flag_ptr[r], flag_color);
                }
                __syncthreads();

                codec.recv(&recv_buffer, &tA[r * Codec::kRankAtoms]);
            }
        }

        // ================= Fused add-residual + RMSNorm epilogue =================
        // tA now holds the all-reduced tile in `ReduceT` format. Each thread owns
        // kAtoms atoms of kElemsPerAtom contiguous elements; every atom lies fully
        // within one hidden-dim row (guaranteed by the host dispatch). We add the
        // residual, write the pre-norm sum to residual_out, reduce sum-of-squares
        // per row through LDS, then normalize and scale by weight.
        using ReduceT = typename std::conditional<cast_bf2half, half, T>::type;

        static constexpr uint32_t kTileElems = kTileSize / sizeof(T);
        // Upper bound on rows per tile (holds for hidden_dim >= 256).
        static constexpr int kMaxRowsPerTile = kTileElems / kAtomStride;

        uint32_t const rows_per_tile = kTileElems / hidden_dim;
        int const nthreads           = blockDim.x * blockDim.y;

        __shared__ float s_rowsum[kMaxRowsPerTile];
        for(int r = thread; r < (int)rows_per_tile; r += nthreads)
        {
            s_rowsum[r] = 0.0f;
        }
        __syncthreads();

        BufferResource res_in_buffer(const_cast<T*>(residual_inp), N * sizeof(T));
        BufferResource res_out_buffer(residual_out, N * sizeof(T));

        // Pass A: x = reduced + residual; write residual_out; accumulate sum(x^2).
        uint32_t off = block * kTileSize + thread * sizeof(int32x4_t);
        for(int i = 0; i < kAtoms; i++)
        {
            ReduceT* red = reinterpret_cast<ReduceT*>(&tA[i]);

            int32x4_t rraw = buffer_load_dwordx4(res_in_buffer.descriptor, off, 0, 0);
            T* resv        = reinterpret_cast<T*>(&rraw);

            uint32_t atom_index = (uint32_t)i * kAtomStride + thread;
            uint32_t row        = (atom_index * kElemsPerAtom) / hidden_dim;

            int32x4_t xraw;
            T* xv       = reinterpret_cast<T*>(&xraw);
            float sumsq = 0.0f;
#pragma unroll
            for(int e = 0; e < kElemsPerAtom; e++)
            {
                float xf = qr_to_float<ReduceT>(red[e]) + qr_to_float<T>(resv[e]);
                sumsq += xf * xf;
                xv[e] = qr_from_float<T>(xf);
            }

            buffer_store_dwordx4(xraw, res_out_buffer.descriptor, off, 0, 0);
            tA[i] = xraw; // stash x for pass B

            if(row < rows_per_tile)
            {
                atomicAdd(&s_rowsum[row], sumsq);
            }
            off += kAtomStride * sizeof(int32x4_t);
        }

        __syncthreads();
        for(int r = thread; r < (int)rows_per_tile; r += nthreads)
        {
            s_rowsum[r] = rsqrtf(s_rowsum[r] / (float)hidden_dim + eps);
        }
        __syncthreads();

        // Pass B: output = x * rsqrt(mean(x^2) + eps) * weight.
        BufferResource out_buffer(output, N * sizeof(T));
        off = block * kTileSize + thread * sizeof(int32x4_t);
        for(int i = 0; i < kAtoms; i++)
        {
            T* xv = reinterpret_cast<T*>(&tA[i]);

            uint32_t atom_index = (uint32_t)i * kAtomStride + thread;
            uint32_t elem0      = atom_index * kElemsPerAtom;
            uint32_t row        = elem0 / hidden_dim;
            uint32_t col0       = elem0 - row * hidden_dim;
            float denom         = (row < rows_per_tile) ? s_rowsum[row] : 0.0f;

            int32x4_t yraw;
            T* yv = reinterpret_cast<T*>(&yraw);
#pragma unroll
            for(int e = 0; e < kElemsPerAtom; e++)
            {
                float xf = qr_to_float<T>(xv[e]);
                float wf = qr_to_float<T>(weight[col0 + e]);
                yv[e]    = qr_from_float<T>(xf * denom * wf);
            }
            buffer_store_dwordx4(yraw, out_buffer.descriptor, off, 0, 0);
            off += kAtomStride * sizeof(int32x4_t);
        }
    }

